#include <stdio.h>
#define MOD 663224321
long long dp[100001];
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        dp[0] = 1;
        for (int i = 1; i <= N; i++) {
            dp[i] = 0;
            for (int j = 0; j < i; j++) {
                dp[i] = (dp[i] + dp[j] * dp[i - j - 1]) % MOD;
            }
        }
        printf("%lld\n", dp[N]);
    }
    return 0;
}

